"use strict";(self.webpackChunkwebpage=self.webpackChunkwebpage||[]).push([[592],{8592:p=>{p.exports=JSON.parse('{"menu":{"company":"회사 소개","team":"팀 소개","rule":"무료 규칙","contact":"문의하기","home":"홈"},"test":"테스트","s1-title1":"무료가 절대 가장 비싼 것은 아닙니다","s1-title2":"엄숙히 선언합니다: 어떠한 상업적 수수수도 없습니다!","s1-title3":"세상에 처리하기 힘든 골칫거리가 없게 하고, 평민들도 손에 익은 도구를 갖게 하겠습니다","s1-title4":"만물 인터넷 - 솔루션 전달","company":{"name":"광주 직장 기아 권진 인터넷 기술 유한공사","address":"광둥성 광주시 황푸구 중산대도 동 280-1호 화영 상업빌딩 303호","description":"안녕하세요, 저는 직장에서 버림받은 기술 개발자 탕린입니다. 제가 앞장서서 설립한 광주 직장 기아 권진 인터넷 기술 유한공사는 갓 설립된 활기차고 혈기 넘치는 기업입니다. 회사 내부 직원들은 모두 직장에서 소외된 평균 경력 5년 이상의 숙련된 기술자들입니다. 모두 제가 업무를 하며 만난 동료이자 친구들로, 저와 마찬가지로 직장에서 밀려났습니다. 직장에 다닐 때부터 줄곧 저만의 회사를 세우고 싶었고, 회사 설립은 필연적인 결과였습니다. 기업 명칭은 다소 자유롭게 정했는데, 이전에는 \\"개인 맞춤형\\"이나 \\"사기업 맞춤형\\"이라는 이름을 생각했지만 제 배경 스토리와 여정을 충분히 표현하지 못한다고 느꼈습니다. 지금의 명칭이 현재 제 상황과 제가 하려는 일을 가장 솔직하게 설명해 준다고 생각합니다. 이러한 운영 방식을 선택한 것은 오늘날 인터넷의 거대한 흐름 덕분입니다. 저희는 공부와 연구를 좋아하는 성실하고 부지런한 팀이며, 연구 성과를 여러분과 공유하고 다양한 도구와 서비스를 무료로 제공하는 것을 즐깁니다. 기술의 최전선에서 탐구하며 혁신이 가져올 수 있는 위험을 여러분을 대신해 기꺼이 감수하겠습니다. 꿈을 쫓는 모든 창업자를 돕기 위해 최선을 다하겠습니다. 저희 회사는 상업용 ERP, CMS, OA 등의 시스템과 미니 프로그램, APP, 그리고 기타 2D 소형 게임을 무료로 맞춤 제작해 드릴 수 있습니다. PC 및 모바일 인터넷 소프트웨어(하드웨어 제외) 제품 분야를 다루며, IoT, AI, OCR, VR/AR, RVC, WRTC 등 첨단 기술 분야의 애플리케이션 개발을 진행합니다. 가능하다면 향후 \\"개인/기업 맞춤형\\" 하드웨어와 소프트웨어를 결합한 관련 비즈니스로 확장하는 것이 저희의 원대한 목표입니다. 저희가 각 산업 분야에서 사용하기 편한 도구를 만드는 데 전념하는 것을 좋아하는 것처럼, 여러분도 저희의 제품과 서비스를 좋아해 주시기를 바랍니다."},"rule":{"contents":"이 페이지 내용","p1":{"title":"시작하며","p11":"개방 - 모든 도구는 GPL 오픈 소스 라이선스를 따릅니다","p12":"자유 - 자유란 하고 싶은 것을 하는 것이 아니라, 하기 싫은 것을 하지 않기로 스스로 선택할 수 있는 것입니다","p13":"공정 - 규모가 작다고 악의적인 경쟁을 하지 않으며, 남에게 해를 끼치고 자신을 이롭게 하지 않으며, 규모가 크다고 독점하지 않습니다","p14":"공개 - 재무 수입과 지출을 투명하게 공개하며, 투명한 서비스를 제공하고, 꼼수를 부리거나 말장난을 하지 않습니다","p15":"꿈이 있는 모든 창업자를 지원하기 위해 최선을 다하겠습니다~"},"p2":{"title":"업계 내막 폭로","p21":"본 회사는 여기서 규칙을 소개하며 누락이나 실수가 있다면 상세히 보완할 것입니다. 동시에 업계의 내막을 폭로하고자 합니다. 흔한 상업적 무료 함정은 다음과 같습니다:","p22":{"p221":"<strong>무료라는 명목으로 사용자를 수확</strong>: 제품 내에 광고가 끊이지 않거나 다른 도구에서 비용을 청구합니다. 흔한 대형 게임이나 앱처럼 다운로드와 플레이는 무료지만, 원활하게 플레이하지 못하게 하거나 즐거운 경험을 주지 않아 사용자가 자발적으로 아이템이나 도구를 구매하게 만듭니다. 요약하자면 <strong>\\"무료가 가장 비싼 것\\"</strong>입니다.","p222":{"p2221":"<strong>무료라는 명목 뒤에 숨겨진 다른 목적.</strong> 무료는 단지 미끼일 뿐이며 진짜 목적은 따로 있습니다. 흔한 무료 APP처럼 겉으로는 무료지만 실제 목적은 사용자 데이터 수집, 다른 유료 서비스 홍보, 심지어 악성 마케팅 활동일 수 있습니다.","p2222":"본질적으로 무료 체험에 해당하며, 만료 후 갱신형 서비스와 같은 경우로 이는 비교적 정상적입니다(3번과 유사).","p2223":"본질은 사기입니다. 무료 제품과 실제 판매 제품이 일치하지 않지만 서로 연관이 있는 경우로, 직업 또는 직무 교육에서 흔히 볼 수 있습니다.","p2224":"본질적으로 교환입니다. 무료를 통해 시장의 한 자리를 차지하려는 것(악의적인 기업은 개인정보나 기타 상업 데이터를 탈취하여 다른 용도로 사용함)으로, 업계에서는 이를 \\"권(卷)\\"이라고 부릅니다.","p2225":"본질적으로 파괴입니다. 무료라는 명목으로 시스템을 파괴하거나 개인 컴퓨터에 침입하여 데이터를 읽는 스크립트가 포함된 크랙 소프트웨어 패치 등이 이에 해당합니다."},"p223":"단점은 숨기고 장점만 홍보하는 방식입니다. 비즈니스 내용을 절반만 말하고 절반은 숨겨 시장 경쟁에 유리하게 홍보하며 사용자의 정서적 가치와 일치하는 부분만 발췌합니다. 여기서 무료는 사실이지만 완전한 제품을 구성하기 위해 필요한 다른 부속품은 유료입니다. 오픈 소스는 사실이지만 문서는 유료인 경우가 대표적입니다."}},"p3":{"title":"저희는 왜 무료인가요?","p31":"저희도 시장에서 한 자리를 차지해야 하며, 이러한 \\"권\\"을 저희는 \\"상권(上卷)\\"이라고 부릅니다. 악의적인 경쟁업체의 무분별한 저가 전략과 노동력 착취 행위인 \\"하권(下卷)\\"과 반대로, \\"상권\\"은 혁신을 통해 새로운 일자리를 창출하고 사회 발전을 이끄는 것을 의미합니다. 이는 생산 효율을 높이고 전통적인 작업 방식을 도태시킵니다. 말하자면 저희는 일종의 혁명을 기획하고 있습니다.","p32":"본질적으로 저희는 여러분의 기술 주주입니다. 모든 창업자가 성공적으로 안착하는 데 필요한 생산 도구를 제공하는 것이 저희의 가장 순수한 목적입니다.","p33":"인터넷 상업화 아래 도구 자체의 가치는 천차만별입니다. 가격이 너무 높으면 아웃소싱이고, 너무 낮으면 소프트웨어를 파는 상업 회사일 뿐입니다. 하지만 현재 경제 상황에서 상업적 도구/소프트웨어 시스템을 개발 원가에 판매하더라도 소비 시장은 이를 수용하기 어렵습니다. 도구는 반드시 제품을 위해 서비스될 때 가치가 나타납니다. 등록 코드 유료 소프트웨어는 단일 문제 해결의 가치 구현이지만, 이러한 소프트웨어는 복제 배포가 가능하므로 개발자 원가로 판매하는 것은 불합리하며, 판매량은 영업 능력과 시장 인지도에 달려 있습니다.","p34":"전문 기술 인력에 대한 기업의 비용 지출을 최대한 줄여, 기업 내의 인력 낭비와 같은 현상을 근본적으로 차단합니다.","p35":"시장에서 소외된 숙련된 구직자들을 모아 현재의 국가 상황과 경제 형식에 적합한 새로운 고용 방식을 탐색하고, 고용에 새로운 에너지를 부여하며, 노동을 재정의하여 완벽에 가까운 프리랜서 생태 환경을 조성합니다.","p36":"각 개인 구성원의 가치를 사회에 최대화하여 출력합니다.","p37":"최적의 해답에 집중: 전통적인 아웃소싱 업계와 달리 저희는 귀하의 예산과 프로젝트 수익성에 따라 적절한 방식과 인원을 매칭합니다. 이익만을 위해 품질을 도외시하는 패스트푸드식 프로젝트를 지양하고 고객에게 최적의 솔루션을 제공합니다."},"p4":{"title":"운영 모드","p41":"프로젝트 운영은 다음 세 가지 관계를 통해 이루어집니다:","p42":{"title":"세 가지 관계","p421":{"title":"1. 협력 관계","p4211":"이름 그대로 양측이 상생하는 방식으로 프로젝트를 공동 책임집니다. 귀하의 아이디어와 요구 사항을 결합하여 귀하만을 위한 도구 제품을 무료로 제작해 드립니다. 주의할 점은 이 모드에서는 프로젝트 수익이 발생한 후에야 저희가 배당을 받기 시작한다는 것입니다. 또한 저희 팀은 제품 매니저, UI, 테스트, 개발, 운영 등 모든 요청에 대응하는 서비스를 포함하므로, 정식 업무 투입 전 저희의 전문 지식에 근거하여 건설적인 제안을 드릴 수 있습니다. 협력 관계는 두 가지 방안을 제공합니다:","p4212":{"title":"모드 1: 비용 회수까지","p42121":"저희는 인건비의 2배만 회수합니다. 비용은 고용 관계 가격의 <a1>제1단계</a1>를 기준으로 계산됩니다. 귀하의 프로젝트에 맞춰 상한과 하한 구간을 정하고, 그 구간 내에서 저희에게 줄 배당 비율을 정의합니다(유연한 할부와 유사하며, 이 비율은 총 매출 대비 비중입니다). 회수될 때까지 귀하의 운영 방식에는 간섭하지 않습니다. 매출 0원이나 부채가 발생한 달에는 배당에 참여하지 않으며, 다음 달에 배당 비율을 조정할 수 있습니다. 회수 후(계약 종료 후) 새로운 기능이나 유지보수 요청이 있다면, 새 기능은 <a2>제2단계</a2>, 유지보수는 <a3>제3단계</a3>를 적용합니다(아래 고용 관계 참조). 계약 종료는 두 가지 방식이 있습니다: 비용 회수에 따른 자연 종료와 기업 파산 또는 팀의 프로젝트 포기에 따른 강제 종료입니다. 자연 종료 이외의 종료 시 고객은 제품 자원 및 저작권 소유권을 가질 수 없습니다."},"p4213":{"title":"모드 2: 기간 만료까지","p42131":"프로젝트 기여도(용어 설명은 아래 참조)에 따라 매월 고정 금액을 수취합니다(고정 할부 방식이며, 이 모드는 평가 모드입니다. 저희의 총 수익은 비용보다 높을 수도 낮을 수도 있으며 양측이 합의한 협약에 따릅니다). 계약에 정해진 기간까지 진행됩니다. 자연 종료가 아닌 경우 프로젝트 기여도 비율에 따라 청산 가치를 수취합니다. 모드 1과 마찬가지로 자연 종료가 아닌 경우 고객은 제품 자원 및 저작권 소유권을 가질 수 없습니다."},"p4214":"이 두 모드의 운영 기간 동안 저희는 별도의 유지보수비를 받지 않으며 끝까지 무료로 진행합니다! 운영 기간 중 추가 기능 구현도 무료로 해드리며, 그에 따른 실제 비용 소모만 추가됩니다.","p4215":"프로젝트 성공 확률이 80% 이상이라고 확신하신다면 두 번째 방안을 추천합니다. 초기 스타트업이거나 투자 유치 중, 혹은 파트너를 찾고 계신다면 첫 번째 방안을 추천합니다.","p4216":"자원이 제3자에게 머무는 것이 우려되거나 고객 자원 및 민감한 데이터를 보호해야 하는 경우, 모드 2에서 짧은 기간을 설정하거나 아래의 고용 관계 방식을 사용하시기 바랍니다."},"p422":{"title":"2. 파트너 관계","p4221":"프로젝트가 훌륭하고 저 개인에 대해 신뢰가 있으시다면, 저 또는 저희 팀 전체가 귀하의 파트너가 될 수 있습니다. 이는 무료를 가장 철저하게 실천하는 방식이며 기술 출자 방식으로 참여합니다. 귀하의 프로젝트가 지속적인 혁신 도구와 업데이트가 필요하거나 업계 최전선에서 탐구 중이라면 파트너 관계가 최적의 해답입니다. 하나의 목표를 위해 분투하는 방식이므로 협의가 필요합니다."},"p423":{"title":"3. 고용 관계","p4231":"시간제 아르바이트 또는 정규직 형태입니다. 근무 장소 제한 없이 시간과 품질을 납품 기준으로 합니다. 8시간을 1일 작업으로 계산하며, 각 팀원은 업계 경력 수준에 따라 가격이 책정되어 있습니다. 이 모드에는 세 가지 가격 단계가 있습니다:","p4232":"제1단계: 각 팀원의 실제 몸값 (팀원 평균 시급 60-75 CNY/h, 상세 자료는 문의 주시면 제공해 드립니다).","p4233":"제2단계: 제1단계에서 15% 할인된 가격.","p4234":"제3단계: 제1단계에서 75% 할인된 가격.","p4235":"참고: 협력 관계와 파트너 관계는 저희가 귀하와 위험을 공동 부담합니다. 협력 관계 모드가 저희의 정체성에 더 부합하며, 모든 프로젝트를 수주하지는 않습니다. 최종 해석권은 프로젝트 팀 구성원들에게 있습니다.","p4236":"고용 관계를 \\"아웃소싱\\"이나 \\"인력 파견\\"과 구분해 주십시오. 견적상의 큰 차이는 없지만(<a1>견적 계산기</a1>) 고용 방식에 뚜렷한 차이가 있습니다. 아웃소싱은 프로젝트 단위의 협력 관계이고, 인력 파견은 인적 자원 단위의 협력 관계입니다. 전자는 명확한 프로젝트 요구 사항이 있는 고객에게, 후자는 지속적인 인력이 필요한 고객에게 적합합니다."}}},"p5":{"title":"자주 묻는 질문","p51":"저희 프로젝트의 매출 상황이나 이익 규모를 어떻게 알 수 있나요?","p52":"운영은 귀하가 하고 데이터 센터는 저희 쪽에 있습니다. 저희는 데이터를 기반으로 평가하므로 재무제표를 볼 필요가 없습니다. 프로젝트를 포기할 경우 자원은 저희 쪽에 남으므로 걱정하실 필요 없습니다.","p53":"서로의 신뢰 문제를 어떻게 보장하나요?","p54":"프로젝트 평가와 생산 가치에 양측 모두 참여해야 합니다. 평가의 신뢰도는 제약 시스템을 함께 만들기 때문에 위험을 공동 부담하는 구조입니다. 소스 코드, 서버, 하드웨어 장비 등은 먼저 저희가 무료로 제공하며, 계약 종료 후 모든 권한을 이전해 드립니다.","p55":"프로젝트 기여도란 무엇인가요?","p56":"프로젝트 기여도는 백분율 값입니다. 귀하를 위해 맞춤 제작된 프로젝트가 전체 운영의 일부분일 수 있기 때문입니다. 계산 공식은: 프로젝트 기여도 = 본 프로젝트로 인한 이익 / 회사 총 이익 * 100% 입니다. 물론 이 \\"이익\\"은 귀하가 직접 평가합니다. 저희는 이 수치가 아무리 작아도 상관없지만, 협력 관계 모드 2에서는 기간을 결정해야 하므로 가급적 정확하게 평가해 주시기 바랍니다.","p57":"프로젝트 중간 포기에 어떻게 대응하나요?","p58":"계약을 체결하며, 갑(고객) 측의 내부 사정으로 인한 포기 시 현재까지의 작업량을 고용 모드 기준으로 배상하며, 그 외의 원인으로 인한 종료 시에는 배상하지 않습니다.","p59":"기타 문의 사항은 연락 주시면 신속히 답변해 드리겠습니다!"},"p6":{"title":"맺음말","p61":"순수하게 돕는 차원으로 기술 파트너가 아닌 지원 형태로 참여하며, 급여 없이 최종 제품 수익으로 보상받습니다. 즉, 프로젝트가 무산되면 저희도 아무것도 얻지 못하는 위험 분담 구조입니다. 자본이 부족하거나 기술 이사를 따로 두지 않으려는 초기 창업자에게 적합합니다. 제품 출시 후 다음 두 가지 상황 중 하나를 선택합니다:","p62":"비용 회수까지 (유연 할부)","p63":"출시 후 매출의 일부를 비율로 수취하며, 수익이 좋으면 조기 결제가 가능합니다. 비율은 프로젝트 수익 능력과 비용을 고려해 직접 정하시면 됩니다. 다만 매출이 1만 원인데 0.0001%를 책정하는 것은 불합리합니다. 이자율은 월 0.25% 단리(말장난이나 수수수 없음)로 시중 은행보다 낮습니다. 비용 공식: 시급 x 프로젝트 주기 x 이자율 x 2입니다. 결제 전에는 기업 명칭, 전화번호, 법인 대표를 변경할 수 없습니다. 자연 종료가 아닌 경우 제품 자원 및 저작권은 고객 소유가 아닙니다.","p64":"기간 만료까지 (고정 할부)","p65":"갑이 프로젝트 수익 능력을 평가하여 제품 가치에 따라 2~5년 정도의 기간을 정해 매월 배당하는 방식입니다. 양측의 평가액이 대체로 일치해야 채택 가능합니다. 위 방식과 달리 수익 여부와 상관없이 정해진 기간까지 고정 배당을 해야 합니다. 종료 방식과 권한 문제는 위 방식과 동일합니다.","p66":"실패할 확률이 높거나 신중하지 않은 프로젝트는 저희도 손해를 보기 때문에 수주하지 않을 확률이 높습니다. 따라서 저희도 프로젝트를 깊이 이해하고 조사와 회의, 투표에 전 과정 참여해야 합니다.","p67":"두 방법 모두 제품을 먼저 만들고 운영을 시작하는 것이 우선입니다. 실행력을 앞세워 문제를 해결해 나갑시다."}},"cal":{"title":"견적 계산기","p1":"가시적 UI","p2":"총 페이지 수","p21":"비가시적 기능","p22":"UI에 나타나지 않는 기능으로, 주로 백엔드 기능이나 프런트엔드 로직 기능(SDK 개발 등)입니다.","p23":"테스트 필요 여부","p24":"버그가 적거나 없는 납품을 보장받으려면 체크를 권장합니다.","p25":"연동 필요 여부","p26":"백엔드 비즈니스 시나리오가 없거나 백엔드 연동이 필요 없는 경우 체크하지 마십시오.","p27":"아키텍처 수","p28":"아키텍처는 프로젝트의 \\"기반\\"입니다. 전체 프로젝트에는 최소 1개의 아키텍처가 필요합니다. 오픈 소스 프레임워크를 그대로 사용한다면 체크하지 않아도 됩니다. 다중 플랫폼 네이티브 개발 시 그 수만큼 아키텍처를 계산합니다. 크로스 플랫폼(하나의 코드로 다중 실행)은 1개로 계산합니다.","p29":"인원수","p210":"해당 프로젝트에 투입되는 인원수로, 최소 1명이 필요합니다.","p211":"결제 방식","p212":"선택해 주세요","p213":"할부 의미의 가격 할인 기준입니다. 세 숫자는 계약 시, 개발 완료 시, 검수 완료 시의 결제 비율을 나타내며 방식에 따라 할인율이 달라집니다.","p214":"프로젝트 기간 평가","p215":"일","p216":"계산 결과:","p217":"계산 시작","hint1":"여기에 수량을 입력하세요","hint2":"계산 결과는 추정치이며 실제와 다를 수 있습니다. 구체적인 내용은 계약서를 기준으로 합니다!","resutlHint":"주: 시간 단위는 시간(h), 가격 단위는 위안(CNY), \'?\' 기호는 요구 사항 누락, \'-\' 기호는 UI에 나타나지 않는 비즈니스 로직, \'x\' 기호는 백엔드와 무관한 업무를 의미합니다."}}')}}]);